# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from itsdangerous import URLSafeTimedSerializer
from flask_mail import Mail, Message
import secrets
import string

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(128), nullable=True)

@app.route('/reset-password', methods=['POST'])
def password_reset():
    data = request.json
    user_email = data.get('email')
    
    if not user_email:
        return jsonify({'error': 'Email is required'}), 400
    
    existing_user = User.query.filter_by(email=user_email).first()
    
    if existing_user and existing_user.reset_token:
        # Token already exists, send email with the token
        send_reset_link(user_email, existing_user.reset_token)
        return jsonify({'message': 'Reset link sent to your email'}), 200
    
    # Generate a new reset token
    token = secrets.token_urlsafe(128)
    
    # Store token in database
    user = User(email=user_email, reset_token=token)
    db.session.add(user)
    db.session.commit()
    
    # Send reset link
    send_reset_link(user_email, token)
    
    return jsonify({'message': 'Reset link sent to your email'}), 200

def send_reset_link(email, token):
    serializer = URLSafeTimedSerializer('secret_key')
    url = serializer.dumps(email)
    msg = Message('Password Reset Link', sender='your-email@example.com', recipients=[email])
    msg.body = f'Click this link to reset your password: http://example.com/reset-password/{url}'
    mail.send(msg)

if __name__ == '__main__':
    app.run(debug=True)